/**
 * Thin wrapper around @docusaurus/plugin-content-blog for the Changelog blog
 * instance.
 *
 * The Changelog is a second instance of the standard blog plugin, so its
 * autogenerated i18n base file
 * (`i18n/en/docusaurus-plugin-content-blog-changelog/options.json`) inherits the
 * generic "blog" translator-context strings the upstream plugin hardcodes in
 * `getTranslationFiles()`. Those strings are byte-for-byte identical to the real
 * Blog instance's, so a Weblate translator cannot tell which is which.
 *
 * This wrapper delegates everything to the upstream plugin and overrides only
 * `getTranslationFiles()`, rewording the translator context to refer to the
 * changelog. Docusaurus calls `plugin.getTranslationFiles()` at build time and
 * during `write-translations`, so the generated base file is fixed at the source
 * (no fragile post-processing) and stays deterministic for the CI drift check.
 *
 * The plugin name and id are left untouched, so the output directory name
 * (`docusaurus-plugin-content-blog-changelog`) is unchanged.
 */

const blogPlugin = require('@docusaurus/plugin-content-blog');

async function blogChangelogPlugin(context, options) {
  const plugin = await blogPlugin.default(context, options);
  return {
    ...plugin,
    getTranslationFiles() {
      return [
        {
          path: 'options',
          content: {
            title: {
              message: options.blogTitle,
              description: 'The title for the changelog used in SEO',
            },
            description: {
              message: options.blogDescription,
              description: 'The description for the changelog used in SEO',
            },
            'sidebar.title': {
              message: options.blogSidebarTitle,
              description: 'The label for the changelog left sidebar',
            },
          },
        },
      ];
    },
  };
}

module.exports = blogChangelogPlugin;
module.exports.validateOptions = blogPlugin.validateOptions;
